import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { useEffect, lazy, Suspense } from 'react';
import { Layout } from './components/Layout';
import { StoreErrorBoundary } from './components/StoreErrorBoundary';
import { migrateToIndexedDB, isMigrationNeeded } from './services/migration';
import { UndoToastContainer } from './components/UndoToast';
import { useUndoStore } from './stores/useUndoStore';
import { OnboardingModal } from './components/OnboardingModal';
import { useSettingsStore } from './stores/useSettingsStore';

// Lazy load all pages for code splitting (including Dashboard)
const Dashboard = lazy(() => import('./pages/Dashboard').then((m) => ({ default: m.Dashboard })));
const Tasks = lazy(() => import('./pages/Tasks').then((m) => ({ default: m.Tasks })));
const Settings = lazy(() => import('./pages/Settings').then((m) => ({ default: m.Settings })));
const Notes = lazy(() => import('./pages/Notes').then((m) => ({ default: m.Notes })));
const GraphView = lazy(() => import('./pages/GraphView'));
const Diagrams = lazy(() => import('./pages/Diagrams'));
const DiagramEditor = lazy(() => import('./pages/DiagramEditor'));
const Forms = lazy(() => import('./pages/Forms'));
const FormBuilder = lazy(() => import('./pages/FormBuilder'));
const FormFiller = lazy(() => import('./pages/FormFiller'));
const FormResponses = lazy(() => import('./pages/FormResponses'));
const TimeTracking = lazy(() => import('./pages/TimeTracking').then((m) => ({ default: m.TimeTracking })));
const LinkLibrary = lazy(() => import('./pages/LinkLibrary'));
const Automations = lazy(() => import('./pages/Automations').then((m) => ({ default: m.Automations })));

// Loading fallback component
const PageLoader = () => (
  <div className="flex items-center justify-center min-h-[60vh]">
    <div className="text-center">
      <div className="inline-block h-12 w-12 animate-spin rounded-full border-4 border-solid border-primary-cyan border-r-transparent align-[-0.125em] motion-reduce:animate-[spin_1.5s_linear_infinite]"></div>
      <p className="mt-4 text-sm text-text-light-secondary dark:text-text-dark-secondary">Loading...</p>
    </div>
  </div>
);

/**
 * Main App Component with React Router
 * Uses Layout component to provide consistent header/footer
 */
function App() {
  // Get undo toasts from store
  const toasts = useUndoStore((state) => state.toasts);
  const dismissToast = useUndoStore((state) => state.dismissToast);

  // First-time onboarding
  const onboardingComplete = useSettingsStore((state) => state.onboardingComplete);
  const setOnboardingComplete = useSettingsStore((state) => state.setOnboardingComplete);

  // Run migration and initialize auto-save on app startup
  useEffect(() => {
    const initialize = async () => {
      // Run migration if needed
      if (isMigrationNeeded()) {
        console.log('🚀 Migration needed, starting...');
        const result = await migrateToIndexedDB();
        if (result.success) {
          console.log('✅ Migration complete');
        } else {
          console.error('❌ Migration failed:', result.errors);
        }
      }

      // Initialize auto-save (dynamic import to reduce main bundle)
      const { autoSaveManager } = await import('./services/autoSave');
      await autoSaveManager.initialize();
    };

    initialize();
  }, []);

  return (
    <BrowserRouter>
      <Layout>
        <Suspense fallback={<PageLoader />}>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route
              path="/notes"
              element={
                <StoreErrorBoundary storeName="notes">
                  <Notes />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/graph"
              element={
                <StoreErrorBoundary storeName="notes">
                  <GraphView />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/diagrams"
              element={
                <StoreErrorBoundary storeName="diagrams">
                  <Diagrams />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/diagrams/:id"
              element={
                <StoreErrorBoundary storeName="diagrams">
                  <DiagramEditor />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/forms"
              element={
                <StoreErrorBoundary storeName="forms">
                  <Forms />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/forms/:id/edit"
              element={
                <StoreErrorBoundary storeName="forms">
                  <FormBuilder />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/forms/:id/fill"
              element={
                <StoreErrorBoundary storeName="forms">
                  <FormFiller />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/forms/:id/responses"
              element={
                <StoreErrorBoundary storeName="forms">
                  <FormResponses />
                </StoreErrorBoundary>
              }
            />
            <Route
              path="/tasks"
              element={
                <StoreErrorBoundary storeName="kanban">
                  <Tasks />
                </StoreErrorBoundary>
              }
            />
            <Route path="/settings" element={<Settings />} />
            <Route
              path="/schedule"
              element={
                <StoreErrorBoundary storeName="calendar">
                  <TimeTracking />
                </StoreErrorBoundary>
              }
            />
            <Route path="/links" element={<LinkLibrary />} />
            <Route
              path="/automations"
              element={
                <StoreErrorBoundary storeName="automation">
                  <Automations />
                </StoreErrorBoundary>
              }
            />
          </Routes>
        </Suspense>
      </Layout>

      {/* Undo Toast Container - Global across all pages */}
      <UndoToastContainer toasts={toasts} onDismiss={dismissToast} />

      {/* First-Time Onboarding Modal - includes backup setup for compatible browsers */}
      <OnboardingModal
        isOpen={!onboardingComplete}
        onClose={() => setOnboardingComplete(true)}
      />
    </BrowserRouter>
  );
}

export default App;

import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useThemeStore } from '../stores/useThemeStore';
import { HeaderClock } from './HeaderClock';

/**
 * Simple Header component - minimal styling
 */
export const Header: React.FC = () => {
  const { mode, toggleTheme } = useThemeStore();
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path;

  return (
    <header className="sticky top-0 z-50 bg-white dark:bg-surface-dark border-b border-border-light dark:border-border-dark">
      <div className="container mx-auto px-4 py-3">
        {/* Top row: Branding + Controls */}
        <div className="flex items-center justify-between gap-4 mb-3">
          {/* Branding */}
          <Link to="/" className="flex items-center gap-3">
            <img
              src="/images/logos/nb3.png"
              alt="Neuman Brain Logo"
              className="h-12 w-12 object-contain rounded-button"
            />
            <div className="flex flex-col">
              <h1 className="text-xl font-bold">
                NEUMAN BRAIN
              </h1>
              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                Ultimate Management Platform
              </p>
            </div>
          </Link>

          {/* Clock + Theme Toggle */}
          <div className="flex items-center gap-2">
            <HeaderClock />
            <button
              onClick={toggleTheme}
              className="p-2 rounded-button border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
              title={`Switch to ${mode === 'dark' ? 'light' : 'dark'} mode`}
            >
              <span className="text-xl">
                {mode === 'dark' ? '☀️' : '🌙'}
              </span>
            </button>
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex items-center gap-2 overflow-x-auto">
          {[
            { to: '/', label: '🏠 Dashboard' },
            { to: '/notes', label: '📝 Notes' },
            { to: '/schedule', label: '📅 Schedule' },
            { to: '/tasks', label: '✓ Tasks' },
            { to: '/settings', label: '⚙️ Settings' },
          ].map(({ to, label }) => (
            <Link
              key={to}
              to={to}
              className={`
                px-3 py-2 rounded-button text-sm font-medium transition-all duration-standard ease-smooth
                ${
                  isActive(to)
                    ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                }
              `}
            >
              {label}
            </Link>
          ))}
        </nav>
      </div>
    </header>
  );
};

