     2→ * Collection Sidebar
     3→ *
     4→ * Sidebar for Link Library showing:
     5→ * - Quick filters (All, Favorites, Archived)
     6→ * - User-created collections
     7→ * - Collection CRUD operations
     8→ */
     9→
    10→import React, { useState, useCallback } from 'react';
    11→import { useLinkLibraryStore } from '../stores/useLinkLibraryStore';
    12→
    13→interface CollectionSidebarProps {
    14→  isCollapsed?: boolean;
    15→  onToggleCollapse?: () => void;
    16→}
    17→
    18→export const CollectionSidebar: React.FC<CollectionSidebarProps> = ({
    19→  isCollapsed = false,
    20→  onToggleCollapse,
    21→}) => {
    22→  const {
    23→    collections,
    24→    links,
    25→    activeCollectionId,
    26→    setActiveCollection,
    27→    addCollection,
    28→    updateCollection,
    29→    deleteCollection,
    30→  } = useLinkLibraryStore();
    31→
    32→  const [isAddingCollection, setIsAddingCollection] = useState(false);
    33→  const [newCollectionName, setNewCollectionName] = useState('');
    34→  const [editingCollectionId, setEditingCollectionId] = useState<string | null>(null);
    35→  const [editingName, setEditingName] = useState('');
    36→
    37→  // Calculate counts
    38→  const totalLinks = Object.keys(links).length;
    39→  const favoriteCount = Object.values(links).filter((l) => l.isFavorite).length;
    40→  const archivedCount = Object.values(links).filter((l) => l.isArchived).length;
    41→
    42→  // Get sorted collections
    43→  const sortedCollections = Object.values(collections).sort(
    44→    (a, b) => a.sortOrder - b.sortOrder
    45→  );
    46→
    47→  // Handle add collection
    48→  const handleAddCollection = useCallback(() => {
    49→    if (newCollectionName.trim()) {
    50→      addCollection({
    51→        name: newCollectionName.trim(),
    52→        linkIds: [],
    53→        isExpanded: true,
    54→      });
    55→      setNewCollectionName('');
    56→      setIsAddingCollection(false);
    57→    }
    58→  }, [newCollectionName, addCollection]);
    59→
    60→  // Handle edit collection
    61→  const handleEditCollection = useCallback(
    62→    (id: string) => {
    63→      if (editingName.trim()) {
    64→        updateCollection(id, { name: editingName.trim() });
    65→        setEditingCollectionId(null);
    66→        setEditingName('');
    67→      }
    68→    },
    69→    [editingName, updateCollection]
    70→  );
    71→
    72→  // Handle delete collection
    73→  const handleDeleteCollection = useCallback(
    74→    (id: string) => {
    75→      if (window.confirm('Delete this collection? Links will not be deleted.')) {
    76→        deleteCollection(id);
    77→        if (activeCollectionId === id) {
    78→          setActiveCollection(null);
    79→        }
    80→      }
    81→    },
    82→    [deleteCollection, activeCollectionId, setActiveCollection]
    83→  );
    84→
    85→  // Start editing
    86→  const startEditing = useCallback((id: string, currentName: string) => {
    87→    setEditingCollectionId(id);
    88→    setEditingName(currentName);
    89→  }, []);
    90→
    91→  if (isCollapsed) {
    92→    return (
    93→      <div className="w-12 flex flex-col items-center py-4 border-r border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
    94→        <button
    95→          onClick={onToggleCollapse}
    96→          className="p-2 rounded-button hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors"
    97→          title="Expand sidebar"
    98→        >
    99→          <span className="text-lg">›</span>
   100→        </button>
   101→      </div>
   102→    );
   103→  }
   104→
   105→  return (
   106→    <div className="w-64 flex flex-col border-r border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark">
   107→      {/* Header */}
   108→      <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark">
   109→        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   110→          Library
   111→        </h3>
   112→        {onToggleCollapse && (
   113→          <button
   114→            onClick={onToggleCollapse}
   115→            className="p-1 rounded hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors"
   116→            title="Collapse sidebar"
   117→          >
   118→            <span className="text-lg">‹</span>
   119→          </button>
   120→        )}
   121→      </div>
   122→
   123→      {/* Quick Filters */}
   124→      <div className="p-2">
   125→        <SidebarItem
   126→          icon="📚"
   127→          label="All Links"
   128→          count={totalLinks}
   129→          isActive={activeCollectionId === null}
   130→          onClick={() => setActiveCollection(null)}
   131→        />
   132→        <SidebarItem
   133→          icon="⭐"
   134→          label="Favorites"
   135→          count={favoriteCount}
   136→          isActive={activeCollectionId === 'favorites'}
   137→          onClick={() => setActiveCollection('favorites')}
   138→        />
   139→        <SidebarItem
   140→          icon="📥"
   141→          label="Archived"
   142→          count={archivedCount}
   143→          isActive={activeCollectionId === 'archived'}
   144→          onClick={() => setActiveCollection('archived')}
   145→        />
   146→      </div>
   147→
   148→      {/* Collections Header */}
   149→      <div className="flex items-center justify-between px-4 py-2 mt-2 border-t border-border-light dark:border-border-dark">
   150→        <span className="text-xs font-medium uppercase tracking-wider text-text-light-secondary dark:text-text-dark-secondary">
   151→          Collections
   152→        </span>
   153→        <button
   154→          onClick={() => setIsAddingCollection(true)}
   155→          className="p-1 rounded hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors"
   156→          title="Add collection"
   157→        >
   158→          <span className="text-sm">+</span>
   159→        </button>
   160→      </div>
   161→
   162→      {/* Add Collection Form */}
   163→      {isAddingCollection && (
   164→        <div className="px-2 py-2">
   165→          <div className="flex items-center gap-2">
   166→            <input
   167→              type="text"
   168→              value={newCollectionName}
   169→              onChange={(e) => setNewCollectionName(e.target.value)}
   170→              onKeyDown={(e) => {
   171→                if (e.key === 'Enter') handleAddCollection();
   172→                if (e.key === 'Escape') {
   173→                  setIsAddingCollection(false);
   174→                  setNewCollectionName('');
   175→                }
   176→              }}
   177→              placeholder="Collection name..."
   178→              autoFocus
   179→              className="flex-1 px-2 py-1 text-sm rounded border border-border-light dark:border-border-dark
   180→                         bg-white dark:bg-surface-dark
   181→                         text-text-light-primary dark:text-text-dark-primary
   182→                         focus:outline-none focus:ring-1 focus:ring-accent-blue"
   183→            />
   184→            <button
   185→              onClick={handleAddCollection}
   186→              className="p-1 text-status-success hover:bg-status-success/10 rounded transition-colors"
   187→            >
   188→              ✓
   189→            </button>
   190→            <button
   191→              onClick={() => {
   192→                setIsAddingCollection(false);
   193→                setNewCollectionName('');
   194→              }}
   195→              className="p-1 text-status-error hover:bg-status-error/10 rounded transition-colors"
   196→            >
   197→              ✕
   198→            </button>
   199→          </div>
   200→        </div>
   201→      )}
   202→
   203→      {/* Collections List */}
   204→      <div className="flex-1 overflow-y-auto p-2">
   205→        {sortedCollections.length === 0 && !isAddingCollection ? (
   206→          <p className="px-2 py-4 text-sm text-center text-text-light-secondary dark:text-text-dark-secondary">
   207→            No collections yet.
   208→            <br />
   209→            <button
   210→              onClick={() => setIsAddingCollection(true)}
   211→              className="text-accent-blue hover:underline mt-1"
   212→            >
   213→              Create one
   214→            </button>
   215→          </p>
