   129→      // Handle paths with query params
   130→      if (child.path.includes('?')) {
   131→        const [pathname, query] = child.path.split('?');
   132→        if (location.pathname !== pathname) return false;
   133→        const params = new URLSearchParams(query);
   134→        const currentParams = new URLSearchParams(location.search);
   135→        for (const [key, value] of params.entries()) {
   136→          if (currentParams.get(key) !== value) return false;
   137→        }
   138→        return true;
   139→      }
   140→      return location.pathname === child.path;
   141→    });
   142→  };
