     5→
     6→/**
     7→ * PageHeader Component
     8→ *
     9→ * Consistent page header with:
    10→ * - Title and optional subtitle (left) - auto-detected from route or explicit props
    11→ * - Optional action buttons (left, below title)
    12→ * - Date & Time display (right) - full format with seconds, AM/PM, timezone
    13→ *
    14→ * Usage Modes:
    15→ * 1. Auto-detect: <PageHeader /> - automatically uses title/subtitle from pageMetadata registry
    16→ * 2. Explicit: <PageHeader title="Custom" subtitle="Description" /> - overrides auto-detect
    17→ *
    18→ * Responsive: Full format on desktop, compact on mobile.
    19→ * Used across all pages for consistent layout.
    20→ */
    21→
    22→interface PageHeaderProps {
    23→  title?: string; // Optional - auto-detected from route if not provided
    24→  subtitle?: string; // Optional - auto-detected from route if not provided
    25→  children?: React.ReactNode; // Action buttons or other content
    26→}
    27→
    28→export const PageHeader: React.FC<PageHeaderProps> = ({ title: titleProp, subtitle: subtitleProp, children }) => {
    29→  const location = useLocation();
    30→
    31→  // Auto-detect title/subtitle from route if not provided via props
    32→  const pageMetadata = getPageMetadata(location.pathname);
    33→  const title = titleProp ?? pageMetadata?.title ?? 'Neuman Brain';
    34→  const subtitle = subtitleProp ?? pageMetadata?.subtitle;
    35→  const timeFormat = useSettingsStore((state) => state.timeFormat);
    36→  const [currentTime, setCurrentTime] = useState(new Date());
    37→
    38→  // Update time every second (for seconds display)
    39→  useEffect(() => {
    40→    setCurrentTime(new Date());
    41→    const interval = setInterval(() => {
    42→      setCurrentTime(new Date());
    43→    }, 1000);
    44→    return () => clearInterval(interval);
    45→  }, []);
    46→
    47→  // Get timezone abbreviation
    48→  const timezone = Intl.DateTimeFormat('en-US', { timeZoneName: 'short' })
    49→    .formatToParts(currentTime)
    50→    .find((part) => part.type === 'timeZoneName')?.value || '';
    51→
    52→  // Format time with seconds, AM/PM
    53→  const formatFullTime = () => {
    54→    if (timeFormat === '24h') {
    55→      return currentTime.toLocaleTimeString('en-US', {
    56→        hour: '2-digit',
    57→        minute: '2-digit',
    58→        second: '2-digit',
    59→        hour12: false,
    60→      });
    61→    }
    62→    return currentTime.toLocaleTimeString('en-US', {
    63→      hour: 'numeric',
    64→      minute: '2-digit',
    65→      second: '2-digit',
    66→      hour12: true,
    67→    });
    68→  };
    69→
    70→  // Format compact time (no seconds, for mobile)
    71→  const formatCompactTime = () => {
    72→    if (timeFormat === '24h') {
    73→      return currentTime.toLocaleTimeString('en-US', {
    74→        hour: '2-digit',
    75→        minute: '2-digit',
    76→        hour12: false,
    77→      });
    78→    }
    79→    return currentTime.toLocaleTimeString('en-US', {
    80→      hour: 'numeric',
    81→      minute: '2-digit',
    82→      hour12: true,
    83→    });
    84→  };
    85→
    86→  // Format full date with year (desktop)
    87→  const fullDateString = currentTime.toLocaleDateString('en-US', {
    88→    weekday: 'long',
    89→    month: 'long',
    90→    day: 'numeric',
    91→    year: 'numeric',
    92→  });
    93→
    94→  // Format compact date (mobile)
    95→  const compactDateString = currentTime.toLocaleDateString('en-US', {
    96→    month: 'short',
    97→    day: 'numeric',
    98→    year: 'numeric',
    99→  });
   100→
   101→  return (
   102→    <div className="flex items-start justify-between gap-4 mb-4 sm:mb-8">
   103→      {/* Left: Title, Subtitle, Actions */}
   104→      <div className="flex-1 min-w-0">
   105→        <h1 className="text-xl sm:text-2xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
   106→          {title}
   107→        </h1>
   108→        {subtitle && (
   109→          <p className="text-sm sm:text-base text-text-light-secondary dark:text-text-dark-secondary mb-2 sm:mb-3">
   110→            {subtitle}
   111→          </p>
   112→        )}
   113→        {children && <div className="flex flex-wrap gap-2">{children}</div>}
   114→      </div>
   115→
   116→      {/* Right: Date & Time - Responsive */}
