     1→/**
     2→ * TagFilter Component
     3→ *
     4→ * Tag-based filtering UI for notes sidebar
     5→ * Features:
     6→ * - Show active tag filters
     7→ * - Add/remove tag filters
     8→ * - Combine tags (AND logic)
     9→ * - Clear all filters
    10→ */
    11→
    12→import React, { useState, useMemo } from 'react';
    13→import { X, Tag as TagIcon, ChevronRight, ChevronDown } from 'lucide-react';
    14→import { useTagCounts } from '../hooks/useTags';
    15→import { buildTagTree, type TagNode } from '../utils/tagHierarchy';
    16→import { useSettingsStore } from '../stores/useSettingsStore';
    17→
    18→interface TagFilterProps {
    19→  /** Currently active tag filters */
    20→  activeTags: string[];
    21→  /** Callback when tag filter is added */
    22→  onAddTag: (tag: string) => void;
    23→  /** Callback when tag filter is removed */
    24→  onRemoveTag: (tag: string) => void;
    25→  /** Callback to clear all filters */
    26→  onClearAll: () => void;
    27→}
    28→
    29→export function TagFilter({ activeTags, onAddTag, onRemoveTag, onClearAll }: TagFilterProps) {
    30→  const tagCounts = useTagCounts();
    31→  const tagColors = useSettingsStore((state) => state.tagColors);
    32→  const [expandedTags, setExpandedTags] = useState<Set<string>>(new Set());
    33→
    34→  // Build tag tree with counts
    35→  const tagCountMap = useMemo(() => {
    36→    const map: Record<string, number> = {};
    37→    tagCounts.forEach(({ tag, count }) => {
    38→      map[tag] = count;
    39→    });
    40→    return map;
    41→  }, [tagCounts]);
    42→
    43→  const allTags = useMemo(() => tagCounts.map(tc => tc.tag), [tagCounts]);
    44→  const tagTree = useMemo(() => buildTagTree(allTags, tagCountMap), [allTags, tagCountMap]);
    45→
    46→  const toggleExpand = (tag: string) => {
    47→    setExpandedTags(prev => {
    48→      const next = new Set(prev);
    49→      if (next.has(tag)) {
    50→        next.delete(tag);
    51→      } else {
    52→        next.add(tag);
    53→      }
    54→      return next;
    55→    });
    56→  };
    57→
    58→  // Recursive function to render tag tree
    59→  const renderTagNode = (node: TagNode): React.ReactNode => {
    60→    const hasChildren = node.children.length > 0;
    61→    const isExpanded = expandedTags.has(node.name);
    62→    const isActive = activeTags.includes(node.name);
    63→
    64→    return (
    65→      <div key={node.name}>
    66→        <button
    67→          onClick={() => {
    68→            if (!hasChildren && !isActive) {
    69→              onAddTag(node.name);
    70→            }
    71→          }}
    72→          disabled={isActive}
    73→          className={`
    74→            w-full flex items-center justify-between px-2 py-1.5 text-sm rounded transition-colors text-left group
    75→            ${isActive
    76→              ? 'opacity-50 cursor-not-allowed'
    77→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
    78→            }
    79→          `}
    80→          style={{ paddingLeft: `${node.level * 16 + 8}px` }}
    81→        >
    82→          <div className="flex items-center gap-2 flex-1 min-w-0">
    83→            {hasChildren && (
    84→              <span
    85→                onClick={(e) => {
    86→                  e.stopPropagation();
    87→                  toggleExpand(node.name);
    88→                }}
    89→                className="flex-shrink-0 cursor-pointer"
    90→              >
    91→                {isExpanded ? (
